```class Solution {
public:
    int minLength(string s) {
        string t = "";
        for (char c : s) {
            if (t.size() && ((t.back() == 'A' && c == 'B') || (t.back() == 'C' && c == 'D'))) {
                t.pop_back();
            } else {
                t.push_back(c);
            }
        }
        return t.size();
    }
};
